initScript:
await ManagerApi.ready();
const baseApi = ManagerApi.getBase();
const siteApiBase = baseApi + '/site';
const dirApiBase = baseApi + '/dir';
const fileApiBase = baseApi + '/file';
const workspaceRoot = (await utils.postForm(siteApiBase + '/get_root.php', {})).trim().replace(/\/$/, '');
const baseDir = workspaceRoot + '/.temp';
return {
  baseDir,
  transferDirName: 'transfer-box',
  transferInnerFileName: 'inner.txt',
  createDirUrl: dirApiBase + '/create_dir.php',
  deleteDirUrl: dirApiBase + '/delete_dir.php',
  scanDirUrl: dirApiBase + '/scan_dir.php',
  scanFileUrl: fileApiBase + '/scan_file.php',
  createFileUrl: fileApiBase + '/create_file.php',
  writeFileUrl: fileApiBase + '/write_file.php',
  readFileUrl: fileApiBase + '/read_file.php',
  uploadFilesUrl: fileApiBase + '/upload_files.php',
  downloadFileUrl: fileApiBase + '/download_file.php',
  downloadDirUrl: dirApiBase + '/download_dir.php',
  message: 'init done'
};

tests.scriptText:
try { await utils.postForm(deleteDirUrl, { path: baseDir + '/' + transferDirName }); } catch (_) {}
const text = await utils.postForm(createDirUrl, { dir: baseDir, name: transferDirName });
const m = text.match(/\[(.+?)\/\]/);
assert(m && m[1], 'create: parse fail');
const dirs = JSON.parse((await utils.postForm(scanDirUrl, { path: baseDir })) || '[]');
assert(Array.isArray(dirs), 'create: scan dir not array');
assert(dirs.includes(transferDirName), 'create: dir missing');
return { transferDirPath: m[1], message: 'created=' + m[1] };

const dragFiles = Array.isArray(selectedUploadDragFiles) ? selectedUploadDragFiles : [];
const dragDirs = Array.isArray(selectedUploadDragDirs) ? selectedUploadDragDirs : [];
if (!dragFiles.length) return { uploadedDragFiles: [], message: 'uploaded drag files=0' };
const dirsParam = dragDirs.map((d) => {
  const rel = String(d || '').replace(/^\/+/, '');
  return rel ? `${transferDirPath}/${rel}` : transferDirPath;
});
const expected = dragFiles.map((f, i) => `${dirsParam[i]}/${f.name}`);
const resp = await utils.postMultipart(uploadFilesUrl, dragFiles, dirsParam);
const data = JSON.parse(resp || '{}');
assert(Array.isArray(data.files), 'upload_drag: response files not array');
assert(data.files.length === expected.length, 'upload_drag: files count mismatch');
for (let i = 0; i < expected.length; i++) {
  assert(data.files[i] === expected[i], `upload_drag: path mismatch @${i}`);
}
return { uploadedDragFiles: data.files, message: 'uploaded drag files=' + data.files.length };

const filesInput = Array.isArray(selectedUploadFiles) ? selectedUploadFiles : [];
if (!filesInput.length) return { uploadedFiles: [], message: 'uploaded files=0' };
const dirsParam = filesInput.map(() => transferDirPath);
const expected = filesInput.map((f) => `${transferDirPath}/${f.name}`);
const resp = await utils.postMultipart(uploadFilesUrl, filesInput, dirsParam);
const data = JSON.parse(resp || '{}');
assert(Array.isArray(data.files), 'upload_file: response files not array');
assert(data.files.length === expected.length, 'upload_file: files count mismatch');
for (let i = 0; i < expected.length; i++) {
  assert(data.files[i] === expected[i], `upload_file: path mismatch @${i}`);
}
return { uploadedFiles: data.files, message: 'uploaded files=' + data.files.length };

const folderFiles = Array.isArray(selectedUploadFolderFiles) ? selectedUploadFolderFiles : [];
if (!folderFiles.length) return { uploadedFolderFiles: [], message: 'uploaded folder files=0' };
const dirname = (p) => { const i = String(p || '').lastIndexOf('/'); return i >= 0 ? p.slice(0, i) : ''; };
const dirsParam = folderFiles.map((f) => {
  const relDir = dirname(f.webkitRelativePath || '');
  return relDir ? `${transferDirPath}/${relDir}` : transferDirPath;
});
const expected = folderFiles.map((f, i) => `${dirsParam[i]}/${f.name}`);
const resp = await utils.postMultipart(uploadFilesUrl, folderFiles, dirsParam);
const data = JSON.parse(resp || '{}');
assert(Array.isArray(data.files), 'upload_folder: response files not array');
assert(data.files.length === expected.length, 'upload_folder: files count mismatch');
for (let i = 0; i < expected.length; i++) {
  assert(data.files[i] === expected[i], `upload_folder: path mismatch @${i}`);
}
return { uploadedFolderFiles: data.files, message: 'uploaded folder files=' + data.files.length };

const text = await utils.postForm(createFileUrl, { dir: transferDirPath, name: transferInnerFileName });
const m = text.match(/\[(.+?)\]/);
assert(m && m[1], 'create_inner_file: parse fail');
await utils.postForm(writeFileUrl, { path: m[1], content: 'hello inner file' });
const readText = await utils.postForm(readFileUrl, { path: m[1] });
assert(readText.includes('hello inner file'), 'create_inner_file: readback mismatch');
const files = JSON.parse((await utils.postForm(scanFileUrl, { path: transferDirPath })) || '[]');
assert(Array.isArray(files), 'create_inner_file: scan file not array');
assert(files.includes(transferInnerFileName), 'create_inner_file: file missing');
return { innerFilePath: m[1], message: 'created+written=' + transferInnerFileName };

const u = `${downloadFileUrl}?path=${encodeURIComponent(innerFilePath)}`;
window.open(u, '_blank');
return { message: 'download_file triggered' };

const u = `${downloadDirUrl}?path=${encodeURIComponent(transferDirPath)}`;
window.open(u, '_blank');
return { message: 'download_dir triggered' };
